import{_ as a,o as t,c as i,ae as r}from"./chunks/framework.BGHOrOyn.js";const c=JSON.parse('{"title":"Safety Setup Page (Failsafes)","description":"","frontmatter":{},"headers":[],"relativePath":"robotics/safety-setup-page-failsafes.md","filePath":"robotics/safety-setup-page-failsafes.md"}'),o={name:"robotics/safety-setup-page-failsafes.md"};function l(s,e,n,h,d,u){return t(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="safety-setup-page-failsafes" tabindex="-1">Safety Setup Page (Failsafes) <a class="header-anchor" href="#safety-setup-page-failsafes" aria-label="Permalink to &quot;Safety Setup Page (Failsafes)&quot;">​</a></h1><p>The Safety Setup page allows you to configure the failsafe settings.</p><h2 id="failsafe-triggers" tabindex="-1">Failsafe Triggers <a href="#failsafe-triggers" id="failsafe-triggers"></a> <a class="header-anchor" href="#failsafe-triggers" aria-label="Permalink to &quot;Failsafe Triggers &lt;a href=&quot;#failsafe-triggers&quot; id=&quot;failsafe-triggers&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>Individual failsafes are triggered when a certain set of conditions are met. Failsafe actions can be configured individually for each failsafe trigger. When a failsafe is triggered, the cooresponding failsafe action is executed. Some failsafes have additional settings that allow you to adjust the trigger conditions, such as maximum acceptable pressure or temperature.</p><p>Failsafe actions are only executed once when a failsafe is triggered. The vehicle can be armed during an active failsafe condition if the arming checks are passing. The flight mode can be changed as long as the failsafe conditions do not prevent it. If an active failsafe is cleared, the failsafe action will be executed again if the failsafe re-triggers.</p><h3 id="gcs-ground-control-station-heartbeat" tabindex="-1">GCS (Ground Control Station) Heartbeat <a href="#gcs-ground-control-station-heartbeat" id="gcs-ground-control-station-heartbeat"></a> <a class="header-anchor" href="#gcs-ground-control-station-heartbeat" aria-label="Permalink to &quot;GCS (Ground Control Station) Heartbeat &lt;a href=&quot;#gcs-ground-control-station-heartbeat&quot; id=&quot;gcs-ground-control-station-heartbeat&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>Triggered when a HEARTBEAT from the ground control station matching SYSID_MYGCS hasn&#39;t been received for more than 2.5 seconds. The failsafe is cleared immediately when a HEARTBEAT is received.</p><p>Note If the system id of the companion computer is a match with SYSID_MYGCS , then the heartebeats originating from a process (ie MAVProxy) on the companion computer may prevent this failsafe from triggering when expected.</p><h4 id="leak" tabindex="-1">Leak <a href="#leak" id="leak"></a> <a class="header-anchor" href="#leak" aria-label="Permalink to &quot;Leak &lt;a href=&quot;#leak&quot; id=&quot;leak&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><p>Triggered immediately when a configured Leak Detector detects a leak. The failsafe is cleared if the leak detector reports no leaks for two seconds.</p><h4 id="battery" tabindex="-1">Battery <a href="#battery" id="battery"></a> <a class="header-anchor" href="#battery" aria-label="Permalink to &quot;Battery &lt;a href=&quot;#battery&quot; id=&quot;battery&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><p>Triggered when the battery voltage drops below the voltage specified by the FS_BATT_VOLTAGE parameter, or if the remaining capacity drops below the capacity specified by the FS_BATT_MAH parameter.</p><h4 id="ekf" tabindex="-1">EKF <a href="#ekf" id="ekf"></a> <a class="header-anchor" href="#ekf" aria-label="Permalink to &quot;EKF &lt;a href=&quot;#ekf&quot; id=&quot;ekf&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><p>Triggered when the EKF compass or velocity variances exceed the threshold set by the FS_EKF_THRESH parameter.</p><h4 id="pilot-input" tabindex="-1">Pilot Input <a href="#pilot-input" id="pilot-input"></a> <a class="header-anchor" href="#pilot-input" aria-label="Permalink to &quot;Pilot Input &lt;a href=&quot;#pilot-input&quot; id=&quot;pilot-input&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><p>Triggered when pilot manual control input has not been received since the amount of time specified by the FS_PILOT_TIMEOUT parameter.</p><h4 id="internal-temperature" tabindex="-1">Internal Temperature <a href="#internal-temperature" id="internal-temperature"></a> <a class="header-anchor" href="#internal-temperature" aria-label="Permalink to &quot;Internal Temperature &lt;a href=&quot;#internal-temperature&quot; id=&quot;internal-temperature&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><p>This is triggered when the internal temperature of the water tight enclosure (WTE) exceeds the threshold set by the FS_TEMP_MAX parameter. The failsafe is cleared immediately when the internal temperature is less than the threshold value.</p><h4 id="internal-pressure" tabindex="-1">Internal Pressure <a href="#internal-pressure" id="internal-pressure"></a> <a class="header-anchor" href="#internal-pressure" aria-label="Permalink to &quot;Internal Pressure &lt;a href=&quot;#internal-pressure&quot; id=&quot;internal-pressure&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><p>This is triggered when the internal pressure of the water tight enclosure (WTE) exceeds the threshold set by the FS_PRESS_MAX parameter for two seconds. The failsafe is cleared immediately when the internal pressure is less than the threshold value.</p><h3 id="failsafe-actions" tabindex="-1">Failsafe Actions <a href="#failsafe-actions" id="failsafe-actions"></a> <a class="header-anchor" href="#failsafe-actions" aria-label="Permalink to &quot;Failsafe Actions &lt;a href=&quot;#failsafe-actions&quot; id=&quot;failsafe-actions&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><h4 id="disabled" tabindex="-1">Disabled <a href="#disabled" id="disabled"></a> <a class="header-anchor" href="#disabled" aria-label="Permalink to &quot;Disabled &lt;a href=&quot;#disabled&quot; id=&quot;disabled&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><p>The failsafe is disabled, and nothing (not even event logging) will happen.</p><h4 id="warn-only" tabindex="-1">Warn Only <a href="#warn-only" id="warn-only"></a> <a class="header-anchor" href="#warn-only" aria-label="Permalink to &quot;Warn Only &lt;a href=&quot;#warn-only&quot; id=&quot;warn-only&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><p>A message will be sent to the ground control station indicating the failsafe conditions have been met. The warning is sent via STATUSTEXT messages, there is no mechanism to immediately re-send the message in the case that it was not received by the ground control station. The warning is sent repeatedly at 20~30 second intervals as long as the failsafe conditions are met.</p><p>These warnings are also sent if the failsafe action is set to anything other than Disabled.</p><h4 id="disarm" tabindex="-1">Disarm <a href="#disarm" id="disarm"></a> <a class="header-anchor" href="#disarm" aria-label="Permalink to &quot;Disarm &lt;a href=&quot;#disarm&quot; id=&quot;disarm&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><p>If the vehicle is armed, the vehicle will disarm immediately when the failsafe conditions are met. The vehicle can be re-armed after the failsafe triggers, even while the failsafe conditions are met, as long as the arming checks are passing. If the failsafe clears due to resolved conditions, the vehicle will disarm again if the failsafe is re-triggered.</p><h4 id="enter-position-or-depth-hold" tabindex="-1">Enter Position or Depth Hold <a href="#enter-position-or-depth-hold" id="enter-position-or-depth-hold"></a> <a class="header-anchor" href="#enter-position-or-depth-hold" aria-label="Permalink to &quot;Enter Position or Depth Hold &lt;a href=&quot;#enter-position-or-depth-hold&quot; id=&quot;enter-position-or-depth-hold&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><p>If the vehicle is armed, the vehicle will enter <strong>Position Hold</strong> mode, or <strong>Depth Hold</strong> mode, if positioning is not possible.</p><h4 id="enter-surface-mode" tabindex="-1">Enter Surface Mode <a href="#enter-surface-mode" id="enter-surface-mode"></a> <a class="header-anchor" href="#enter-surface-mode" aria-label="Permalink to &quot;Enter Surface Mode &lt;a href=&quot;#enter-surface-mode&quot; id=&quot;enter-surface-mode&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><p>If the vehicle is armed, the vehicle will enter Surface flight mode. The flight mode can be changed by the pilot, and the vehicle may be disarmed at any point.</p><h3 id="arming-checks" tabindex="-1">Arming Checks <a href="#arming-checks" id="arming-checks"></a> <a class="header-anchor" href="#arming-checks" aria-label="Permalink to &quot;Arming Checks &lt;a href=&quot;#arming-checks&quot; id=&quot;arming-checks&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>This panel sets which Pre-ARM Safety Checks are enabled.</p><p>Arming checks are enabled and disabled individually. This is a list of arming checks that may be enabled. Arming checks are performed each time there is an attempt to arm the vehicle.</p><h4 id="all" tabindex="-1">All <a href="#all" id="all"></a> <a class="header-anchor" href="#all" aria-label="Permalink to &quot;All &lt;a href=&quot;#all&quot; id=&quot;all&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><p>All of the arming checks are performed.</p><h4 id="barometer" tabindex="-1">Barometer <a href="#barometer" id="barometer"></a> <a class="header-anchor" href="#barometer" aria-label="Permalink to &quot;Barometer &lt;a href=&quot;#barometer&quot; id=&quot;barometer&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><p>Fails if any of the <em>Barometers</em> detected at boot are unhealthy. <em>bug</em></p><h4 id="compass" tabindex="-1">Compass <a href="#compass" id="compass"></a> <a class="header-anchor" href="#compass" aria-label="Permalink to &quot;Compass &lt;a href=&quot;#compass&quot; id=&quot;compass&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><p>Fails if the on board compass is enabled and any of the following are true:</p><ul><li>The compass is unhealthy</li><li>The compass offsets have not been set and learning offsets is disabled</li><li>The compass is currently calibrating</li><li>The compass calibration requires a reboot</li><li>The compass offsets are too large</li><li>The current magnetic field vector length is too large</li><li>Individual compasses have inconsistent measurements</li></ul><h4 id="gps-lock" tabindex="-1">GPS lock <a href="#gps-lock" id="gps-lock"></a> <a class="header-anchor" href="#gps-lock" aria-label="Permalink to &quot;GPS lock &lt;a href=&quot;#gps-lock&quot; id=&quot;gps-lock&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><blockquote><p>This feature requires an under water positioning system. A GPS antenna will not work under water.</p></blockquote><p>Fails if the home position is unset and the GPS is not reporting a 3D fix.</p><h4 id="ins" tabindex="-1">INS <a href="#ins" id="ins"></a> <a class="header-anchor" href="#ins" aria-label="Permalink to &quot;INS &lt;a href=&quot;#ins&quot; id=&quot;ins&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><p>Fails if</p><ul><li>Any of the gyros are unhealthy</li><li>Any of the gyros have a poor calibration</li><li>Any of the accelerometers are unhealthy</li><li>Any of the accelerometers have a poor calibration</li><li>The accelerometer calibration requires a reboot</li><li>Individual accelerometers have inconsistent measurements</li><li>Individual gyros have inconsistent measurements</li><li>The AHRS is unhealthy</li></ul><h4 id="parameters" tabindex="-1">Parameters <a href="#parameters" id="parameters"></a> <a class="header-anchor" href="#parameters" aria-label="Permalink to &quot;Parameters &lt;a href=&quot;#parameters&quot; id=&quot;parameters&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><p>Does nothing! Not Implemented.</p><h4 id="rc" tabindex="-1">RC <a href="#rc" id="rc"></a> <a class="header-anchor" href="#rc" aria-label="Permalink to &quot;RC &lt;a href=&quot;#rc&quot; id=&quot;rc&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><p>Fails if the configured RC input ranges are invalid.</p><h4 id="board-voltage" tabindex="-1">Board voltage <a href="#board-voltage" id="board-voltage"></a> <a class="header-anchor" href="#board-voltage" aria-label="Permalink to &quot;Board voltage &lt;a href=&quot;#board-voltage&quot; id=&quot;board-voltage&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><blockquote><p>This feature is not supported on all boards</p></blockquote><p>Fails if the board voltage is below 4.3V or above 5.8V.</p><h4 id="battery-level" tabindex="-1">Battery Level <a href="#battery-level" id="battery-level"></a> <a class="header-anchor" href="#battery-level" aria-label="Permalink to &quot;Battery Level &lt;a href=&quot;#battery-level&quot; id=&quot;battery-level&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><p>Fails if the battery failsafe is active, of if a battery voltage is below the threshold configured by the <em>ARMING_MIN_VOLT</em> or <em>ARMING_MIN_VOLT2</em> parameters.</p><h4 id="airspeed" tabindex="-1">Airspeed <a href="#airspeed" id="airspeed"></a> <a class="header-anchor" href="#airspeed" aria-label="Permalink to &quot;Airspeed &lt;a href=&quot;#airspeed&quot; id=&quot;airspeed&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><blockquote><p>This setting does not apply to ArduSub. It <em>should</em> have no effect, and should be left at the default value. It will be removed in the future.</p></blockquote><h4 id="logging-available" tabindex="-1">Logging Available <a href="#logging-available" id="logging-available"></a> <a class="header-anchor" href="#logging-available" aria-label="Permalink to &quot;Logging Available &lt;a href=&quot;#logging-available&quot; id=&quot;logging-available&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><p>Fails if there is no SD card inserted or if writing a log failed.</p><h4 id="hardware-safety-switch" tabindex="-1">Hardware Safety switch <a href="#hardware-safety-switch" id="hardware-safety-switch"></a> <a class="header-anchor" href="#hardware-safety-switch" aria-label="Permalink to &quot;Hardware Safety switch &lt;a href=&quot;#hardware-safety-switch&quot; id=&quot;hardware-safety-switch&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><p>Fails if the hardware safety switch is enabled and the hardware safety switch is not in the armed state. The hardware switch is optional, it can be cumbersome to access the electronics in order to arm the autopilot at the hardware level. This is normally diabled.</p><h4 id="gps-configuration" tabindex="-1">GPS Configuration <a href="#gps-configuration" id="gps-configuration"></a> <a class="header-anchor" href="#gps-configuration" aria-label="Permalink to &quot;GPS Configuration &lt;a href=&quot;#gps-configuration&quot; id=&quot;gps-configuration&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><p>Fails if any of the following is true:</p><ul><li>Any gps requires further configuration.</li><li>Individual gps inputs are giving inconsistent readings.</li><li>Blending of multiple gps inputs is unhealthy.</li></ul>',66)])])}const g=a(o,[["render",l]]);export{c as __pageData,g as default};
